VALUES
  ('real-estate-moex-01422', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依實務見解，關於地籍、地用與地稅的敘述，下列何者錯誤？', '["甲有已登記的A地，在占有人乙向地政機關申請時效取得地上權登記之前，甲向乙提起拆屋還地訴訟， 倘乙於該訴訟繫屬中提起反訴，請求確認其地上權登記請求權存在及命甲容忍其辦理地上權登記，且 其提起反訴於程序上並無不合，法院自應就其為訴訟標的之法律關係存否，為實體上裁判", "甲有一工廠之A鐵塔，為專供機械設備用之建築物，可認為非房屋稅課徵之對象", "原住民甲於山坡地範圍內的A原住民保留地取得農育權，並繼續自行經營滿5年，則甲得無償取得A 地所有權", "甲將其A基地出租於乙蓋B屋，於租賃期間，B屋因故滅失，則甲得收回A地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01423', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲有A地與坐落A地上之B屋，但僅將A地自願出賣並移轉於乙；經查B屋並非區分所有建物，亦非 農舍。下列敘述何者正確？', '["甲僅將A地出賣並移轉於乙，違反處分一體化的法律規定", "甲與乙間就A地視為已有租賃關係", "甲與乙間就A地有法定地上權關係", "日後甲出賣其B屋時，乙得主張先買權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01424', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲、乙、丙、丁、戊、己等六人分別共有A地，其中的甲、乙、丙、丁將A地全部出賣給戊。依近年最 高法院判決見解，下列敘述何者正確？', '["甲、乙、丙、丁得將A地有償處分給戊", "甲、乙、丙、丁不得將A地有償處分給戊，因為共有人不得為土地法第34條之1第1項的受讓人", "甲、乙、丙、丁不得將A地有償處分給戊，因為有利害衝突顯失公平情形，難認正當", "甲、乙、丙、丁將A地出賣給戊時，因為並非出賣應有部分，故己不得主張先買權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01425', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '關於優先購買權之種類與效力，依土地法第104條規定，下列何者正確？', '["基地出賣時，長期占有人具有優先購買權", "基地出賣時，地上權人、典權人與承租人有依同樣條件優先購買之權，其順序以抽籤決定之", "基地出賣時，優先購買權人於接到通知後30日內未表示者，視同放棄優先購買權", "基地出賣時，地上權人之優先購買權效力大於共有土地他共有人之優先購買權效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01426', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '有關土地徵收補償之性質，下列何者正確？', '["補償內容僅有地價補償", "屬於一般犧牲", "屬於損害賠償", "屬於損失補償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01427', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲未依法繳納契稅，請問目前應移送何處強制執行？', '["普通法院", "行政法院", "法務部行政執行署所屬行政執行分署", "財政部國有財產署"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01428', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依平均地權條例規定，為避免私人壟斷，應對私有土地面積有最高額之限制。其相關限制內容，下列何 者正確？', '["對於未建築私有建築用地最高面積以10公畝為限", "對於宅地最高面積以10公畝為限", "超額土地當於1年內出售", "逾期未出售之土地，政府得予以徵收"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01429', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲有A地一筆，並將A地出賣給乙，約定由乙負擔以應辦理所有權移轉登記日當期之公告土地現值計算 之土地增值稅；但甲遲延辦理A地所有權移轉登記，致乙多繳稅額。下列敘述何者正確？', '["依目前最高法院見解，由乙負擔土地增值稅的約定係屬無效", "依目前行政法院見解，由乙負擔土地增值稅的約定係屬違憲", "依目前最高法院見解，乙得向甲請求給付遲延的損害賠償", "依目前最高法院見解，乙不得向甲請求賠償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01430', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '關於地用與徵收的敘述，下列何者正確？', '["甲於90年將A耕地出租於乙，則須經甲同意，乙始得將A地轉租於丙", "甲的A地被徵收，卻拒絕受領補償費，則於該補償費繳存土地徵收補償費保管專戶保管時，甲喪失A 地所有權", "甲將其A地出租於乙，如市地重劃後該租賃權消滅，則乙得主張具物權效力的先買權而請求塗銷因市 地重劃而為之A地所有權移轉登記", "甲於90年將位於苗栗縣的A耕地出租於乙，如因市地重劃致不能達原租賃目的，則由苗栗縣政府註銷 其租約並通知甲與乙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01431', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'essay', '最近國內房地產市場呈現不景氣狀況，此一現象在不動產估價原則來說是屬於那一
